7534	 * in an effort to decrease CoW during fork. For small allocations, we can't
7535	 * release any full page, so in an effort to avoid getting the size of the
7536	 * allocation from the allocator (malloc_size) when we already know it's small,
7537	 * we check the size_hint. If the size is not already known, passing a size_hint
7538	 * of 0 will lead the checking the real size of the allocation.
7539	 * Also please note that the size may be not accurate, so in order to make this
7540	 * solution effective, the judgement for releasing memory pages should not be
7541	 * too strict. */
7542	void dismissMemory(void* ptr, size_t size_hint) {
7543	    if (ptr == NULL) return;
7544	
7545	    /* madvise(MADV_DONTNEED) can not release pages if the size of memory
7546	     * is too small, we try to release only for the memory which the size
7547	     * is more than half of page size. */
7548	    if (size_hint && size_hint <= server.page_size/2) return;
7549	
7550	    zmadvise_dontneed(ptr);
7551	}
