1956	static int rdbSaveInternal(int req, const char *filename, rdbSaveInfo *rsi, int rdbflags) {
1957	    char cwd[MAXPATHLEN]; /* Current working dir path for error messages. */
1958	    rio rdb;
1959	    int error = 0;
1960	    int saved_errno;
1961	    char *err_op;    /* For a detailed log */
1962	
1963	    FILE *fp = fopen(filename,"w");
1964	    if (!fp) {
1965	        saved_errno = errno;
1966	        char *str_err = strerror(errno);
1967	        char *cwdp = getcwd(cwd,MAXPATHLEN);
1968	        serverLog(LL_WARNING,
1969	            "Failed opening the temp RDB file %s (in server root dir %s) "
1970	            "for saving: %s",
1971	            filename,
1972	            cwdp ? cwdp : "unknown",
1973	            str_err);
1974	        errno = saved_errno;
1975	        return C_ERR;
1976	    }
1977	
1978	    rioInitWithFile(&rdb,fp);
1979	
1980	    if (server.rdb_save_incremental_fsync) {
1981	        rioSetAutoSync(&rdb,REDIS_AUTOSYNC_BYTES);
1982	        if (!(rdbflags & RDBFLAGS_KEEP_CACHE)) rioSetReclaimCache(&rdb,1);
1983	    }
1984	
1985	    if (rdbSaveRio(req,&rdb,&error,rdbflags,rsi) == C_ERR) {
1986	        errno = error;
1987	        err_op = "rdbSaveRio";
1988	        goto werr;
1989	    }
1990	
1991	    /* Make sure data will not remain on the OS's output buffers */
1992	    if (fflush(fp)) { err_op = "fflush"; goto werr; }
1993	    if (fsync(fileno(fp))) { err_op = "fsync"; goto werr; }
1994	    if (!(rdbflags & RDBFLAGS_KEEP_CACHE) && reclaimFilePageCache(fileno(fp), 0, 0) == -1) {
1995	        serverLog(LL_NOTICE,"Unable to reclaim cache after saving RDB: %s", strerror(errno));
1996	    }
1997	    if (fclose(fp)) { fp = NULL; err_op = "fclose"; goto werr; }
1998	
1999	    return C_OK;
2000	
